                {"swissGerman": "Bruttolohn / Nettolohn", "german": "Bruttolohn / Nettolohn", "explanation": "Same terms in both. 'Brutto' = gross, 'Netto' = net."},
                {"swissGerman": "AHV", "german": "AHV", "explanation": "'Alters- und Hinterlasseneversicherig' — Swiss social security / pension system."},
                {"swissGerman": "Pensionskasse", "german": "Pensionskasse", "explanation": "Swiss occupational pension fund (2nd pillar). Key institution."},
                {"swissGerman": "Probeziit", "german": "Probezeit", "explanation": "'Probeziit' = 'Probezeit'. Probation period."},
                {"swissGerman": "Chündigungsfrischt", "german": "Kündigungsfrist", "explanation": "'Chündigungsfrischt' = 'Kündigungsfrist'. Notice period."},
