                {"swissGerman": "BVG", "german": "BVG", "explanation": "'Berufliche Vorsorge Gesetz' — occupational pension law (2nd pillar)."},
                {"swissGerman": "ALV", "german": "ALV", "explanation": "'Arbeitslosenversicherung' — unemployment insurance."},
